// Stands in for the real AI Agent node (OpenAI/Gemini/Claude + KB RAG + CRM lookup tool + structured output parser).
// Uses simple keyword rules instead of a live LLM call, so this runs with zero API keys.
// Output shape matches the real node's structured-output schema exactly, so all downstream
// nodes (Route by Category/Priority, Route Reply by Channel, logging) work unmodified.
const results = [];
for (const item of $input.all()) {
  const body = (item.json.body || '').toLowerCase();
  let category = 'general';
  let priority = 'standard';
  let summary = 'Routine inquiry, canned reply drafted.';
  let suggested_reply = "Thanks for reaching out! Our support hours are Mon-Fri 9am-6pm ET. Let us know if you have any other questions.";
  let needs_human = false;

  if (body.includes('refund') || body.includes('angry') || body.includes('urgent') || body.includes('charged twice')) {
    category = 'billing';
    priority = 'urgent';
    summary = 'Customer reports a double charge and no refund -- escalate to a human.';
    suggested_reply = '';
    needs_human = true;
  } else if (body.includes('win a free') || body.includes('click this link') || body.includes('prize')) {
    category = 'spam';
    priority = 'standard';
    summary = 'Detected as spam/promotional content.';
    suggested_reply = '';
    needs_human = false;
  }

  results.push({ json: { ...item.json, output: { category, priority, summary, suggested_reply, needs_human } } });
}
return results;

// Stands in for the real Google Sheets append. Prints what the row would have been.
return $input.all().map((item) => ({
  json: {
    mock_action: 'Would append row to Ops Log sheet',
    row: {
      timestamp: new Date().toISOString(),
      channel: item.json.channel,
      from: item.json.from,
      subject: item.json.subject,
      category: item.json.output.category,
      priority: item.json.output.priority,
      summary: item.json.output.summary,
      needs_human: item.json.output.needs_human
    }
  }
}));

// Stands in for the real POST to the CRM Worker's /v1/tickets endpoint.
// Response shape matches crm-worker/src/index.js exactly (created, ticket_id).
return $input.all().map((item, i) => ({
  json: {
    mock_action: 'Would POST to CRM_WORKER_BASE_URL/v1/tickets',
    request_body: {
      email: item.json.from,
      subject: item.json.subject,
      summary: item.json.output.summary,
      priority: 'high',
      channel: item.json.channel
    },
    mock_response: { created: true, ticket_id: 9000 + i }
  }
}));

// Stands in for the real LINE/Telegram/WhatsApp ops notification fan-out.
return $input.all().map((item) => ({
  json: {
    mock_action: 'Would notify ops team on LINE + Telegram + WhatsApp',
    message: `Urgent ${item.json.channel} message from ${item.json.from}: ${item.json.output.summary}`
  }
}));
